using System;
using UnityEngine;
using UnityEngine.UI;

public class PlayerStats : MonoBehaviour
{
    public float health = 100f;
    public float maxHealth = 100f;
    public int currency = 0;
    public int premiumCurrency = 0;
    public int damage = 10;

    public bool IsAlive
    {
        get { return health > 0f; }
    }

    public void TakeDamage(float amount)
    {
        if (amount < 0f) return;
        health = Mathf.Max(0f, health - amount);
    }

    public void Heal(float amount)
    {
        if (amount < 0f) return;
        health = Mathf.Min(maxHealth, health + amount);
    }

    public bool CanAfford(int cost)
    {
        return currency >= cost;
    }

    public bool CanAffordPremium(int cost)
    {
        return premiumCurrency >= cost;
    }

    public bool SpendCurrency(int cost)
    {
        if (cost < 0) return false;
        if (!CanAfford(cost)) return false;
        currency -= cost;
        return true;
    }

    public bool SpendPremiumCurrency(int cost)
    {
        if (cost < 0) return false;
        if (!CanAffordPremium(cost)) return false;
        premiumCurrency -= cost;
        return true;
    }

    public void AddCurrency(int amount)
    {
        if (amount < 0) return;
        currency += amount;
    }

    public void AddPremiumCurrency(int amount)
    {
        if (amount < 0) return;
        premiumCurrency += amount;
    }

    public void AddDamage(int amount)
    {
        if (amount < 0) return;
        damage += amount;
    }
}

[Serializable]
public class ShopItem
{
    public string itemId;
    public string displayName;
    public int basePrice = 10;
    public float priceMultiplier = 1.15f;
    public int baseDamageBonus = 1;
    public int currencyCost = 0;
    public int premiumCost = 0;

    public int CalculatePrice(int quantity)
    {
        if (quantity < 1) quantity = 1;
        float price = basePrice;
        for (int i = 1; i < quantity; i++)
        {
            price *= priceMultiplier;
        }
        return Mathf.Max(0, Mathf.RoundToInt(price));
    }

    public int CalculateDamageBonus(int quantity)
    {
        if (quantity < 1) quantity = 1;
        return baseDamageBonus * quantity;
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public ShopItem[] items;

    public bool BuyItem(int itemIndex, int quantity)
    {
        if (playerStats == null) return false;
        if (items == null || itemIndex < 0 || itemIndex >= items.Length) return false;

        ShopItem item = items[itemIndex];
        int price = item.CalculatePrice(quantity);
        int damageBonus = item.CalculateDamageBonus(quantity);

        bool purchased = false;

        if (item.premiumCost > 0)
        {
            int totalPremiumCost = item.premiumCost * Mathf.Max(1, quantity);
            purchased = playerStats.SpendPremiumCurrency(totalPremiumCost);
        }
        else
        {
            int totalCurrencyCost = price + (item.currencyCost * Mathf.Max(1, quantity));
            purchased = playerStats.SpendCurrency(totalCurrencyCost);
        }

        if (!purchased) return false;

        playerStats.AddDamage(damageBonus);
        return true;
    }
}

public class CombatController : MonoBehaviour
{
    public PlayerStats playerStats;
    public float enemyAttackPower = 5f;

    public void EnemyHitsPlayer()
    {
        if (playerStats == null) return;
        float finalDamage = CalculateDamageOnClient(enemyAttackPower, playerStats.damage);
        playerStats.TakeDamage(finalDamage);
    }

    public float CalculateDamageOnClient(float baseDamage, int playerDamage)
    {
        float bonus = Mathf.Max(0, playerDamage) * 0.5f;
        return Mathf.Max(1f, baseDamage + bonus);
    }
}

public class UIManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public Text healthText;
    public Text currencyText;
    public Text premiumCurrencyText;
    public Text damageText;

    private void Update()
    {
        if (playerStats == null) return;

        if (healthText != null)
            healthText.text = "HP: " + Mathf.CeilToInt(playerStats.health) + "/" + Mathf.CeilToInt(playerStats.maxHealth);

        if (currencyText != null)
            currencyText.text = "Coins: " + playerStats.currency;

        if (premiumCurrencyText != null)
            premiumCurrencyText.text = "Gems: " + playerStats.premiumCurrency;

        if (damageText != null)
            damageText.text = "Damage: " + playerStats.damage;
    }
}